CREATE OR REPLACE FUNCTION public.is_admin_v2(uid uuid) RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER AS $$ BEGIN RETURN EXISTS ( SELECT 1 FROM public.profiles WHERE id = uid AND role IN (
        'super_admin',
        'dev_manager'
    ) AND is_active = true ); END; $$; CREATE OR REPLACE FUNCTION public.is_subordinate_v2(manager_uuid uuid, subordinate_uuid uuid) RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER AS $$ BEGIN IF manager_uuid IS NULL OR subordinate_uuid IS NULL THEN RETURN FALSE; END IF; IF manager_uuid = subordinate_uuid THEN RETURN TRUE; END IF; RETURN EXISTS ( WITH RECURSIVE subordinates AS ( SELECT id, manager_id FROM public.profiles WHERE manager_id = manager_uuid UNION ALL SELECT p.id, p.manager_id FROM public.profiles p INNER JOIN subordinates s ON p.manager_id = s.id ) SELECT 1 FROM subordinates WHERE id = subordinate_uuid ); END; $$; CREATE POLICY profiles_select_policy ON public.profiles FOR SELECT TO authenticated USING ( (id = auth.uid()) OR public.is_admin_v2(auth.uid()) OR public.is_subordinate_v2(auth.uid(), id) ); CREATE POLICY profiles_all_policy ON public.profiles FOR ALL TO authenticated USING ( public.is_admin_v2(auth.uid()) OR public.is_subordinate_v2(auth.uid(), id) ) WITH CHECK ( public.is_admin_v2(auth.uid()) OR public.is_subordinate_v2(auth.uid(), id) );
